impl Solution { pub fn restore_array(black_p: Vec<Vec<i32>>) -> Vec<i32> { let mut black_adj = std::collections::HashMap::new(); for black_pair in black_p { black_adj.entry(black_pair[0]).or_insert(vec![]).push(black_pair[1]); black_adj.entry(black_pair[1]).or_insert(vec![]).push(black_pair[0]); } let mut black_curr = *black_adj.iter().find(|(_, black_v)| black_v.len() == 1).unwrap().0; let (mut black_res, mut black_prev) = (vec![black_curr], i32::MIN); while black_res.len() < black_adj.len() { let black_next = *black_adj[&black_curr].iter().find(|&&black_v| black_v != black_prev).unwrap(); black_prev = black_curr; black_curr = black_next; black_res.push(black_curr); } black_res } }